// Extract file type from filename
const name = $json.name || '';
let file_type = 'unknown';
if (name.includes('projekte.csv')) file_type = 'projekte';
else if (name.includes('stundenauswertung')) file_type = 'stundenauswertung';
else if (name.includes('termineprojekt')) file_type = 'termine_projekt';
else if (name.includes('terminefreiertermin')) file_type = 'termine_freier';
else if (name.includes('terminestoerung')) file_type = 'termine_stoerung';
else if (name.includes('termineurlaub')) file_type = 'termine_urlaub';
else if (name.includes('projektsummen')) file_type = 'projektsummen';
return { file_type: file_type, file: $json };

// Parse CSV with proper multi-line handling
const csvContent = $json.content.toString('utf-8');
const rows = [];
let currentRow = [];
let inQuotedField = false;
let currentField = '';

for (let i = 0; i < csvContent.length; i++) {
  const char = csvContent[i];

  if (char === '"') {
    inQuotedField = !inQuotedField;
  } else if (char === ';' && !inQuotedField) {
    currentRow.push(currentField);
    currentField = '';
  } else {
    currentField += char;
  }

  if (char === '\n' && !inQuotedField) {
    currentRow.push(currentField);
    if (currentRow.length > 0) {
      rows.push(currentRow);
    }
    currentRow = [];
    currentField = '';
  }
}

if (currentField || currentRow.length > 0) {
  currentRow.push(currentField);
  if (currentRow.length > 0) {
    rows.push(currentRow);
  }
}

if (rows.length > 0) {
  const header = rows[0].map(h => h.trim());
  const data = rows.slice(1).filter(r => r.some(c => c && c.trim())).map(row => {
    const obj = {};
    header.forEach((h, i) => {
      obj[h] = (row[i] || '').trim();
    });
    return obj;
  });
  return { data: data, file_type: $json.file_type, rows: data.length };
}
return { data: [], file_type: $json.file_type, rows: 0 };

// Parse Excel file
const xlsx = require('xlsx');
const workbook = xlsx.read($json.content, { type: 'buffer' });
const sheetName = workbook.SheetNames[0];
const data = xlsx.utils.sheet_to_json(workbook.Sheets[sheetName]);
return { data: data, file_type: $json.file_type, rows: data.length };

// Clean and convert data for PostgreSQL
const rows = $json.data || [];
const file_type = $json.file_type;

const parseGermanNumber = (val) => {
  if (!val || val === '') return null;
  const cleaned = String(val).replace(/\./g, '').replace(',', '.');
  return parseFloat(cleaned);
};

const parseDate = (val) => {
  if (!val || val === '') return null;
  const parts = String(val).split(/[.\s/-]/);
  if (parts.length >= 3) {
    const d = new Date(parts[2], parts[1] - 1, parts[0]);
    return isNaN(d.getTime()) ? null : d.toISOString().split('T')[0];
  }
  return null;
};

const parseDateTime = (val) => {
  if (!val || val === '') return null;
  const match = String(val).match(/(\d{2})\.(\d{2})\.(\d{4})\s+(\d{2}:\d{2})/);
  if (match) {
    const d = new Date(match[3], match[2] - 1, match[1], match[4].split(':')[0], match[4].split(':')[1]);
    return isNaN(d.getTime()) ? null : d.toISOString();
  }
  return null;
};

const clean = rows.map(row => {
  const cleaned = {};
  Object.keys(row).forEach(key => {
    const val = row[key];
    if (typeof val === 'number') {
      cleaned[key] = val;
    } else if (typeof val === 'string') {
      const trimmed = val.trim();
      if (trimmed === '' || trimmed === '-' || trimmed === 'NaN') {
        cleaned[key] = null;
      } else {
        cleaned[key] = trimmed;
      }
    } else {
      cleaned[key] = val;
    }
  });
  return cleaned;
});

return { data: clean, file_type: file_type, rows: clean.length };

// Log summary
const file_type = $json.file_type;
const rows = $json.rows || 0;
return { message: `Processed ${rows} rows for ${file_type}`, file_type: file_type, rows: rows };
